#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>
#include <errno.h>

#define MG_DIR ".minigit"
#define INDEX_FILE "index"
#define INDEX_PATH MG_DIR "/" INDEX_FILE
#define MG_VERSION "1"

void fatal(const char *msg) {
    fprintf(stderr, "fatal: %s\n", msg);
    exit(1);
}

void ensure_minigit_dir() {
    struct stat st;
    if (stat(MG_DIR, &st) != 0) {
        if (mkdir(MG_DIR, 0755) != 0) {
            fatal("could not create .minigit directory");
        }
    }
}

void cmd_init() {
    struct stat st;
    if (stat(MG_DIR, &st) == 0) {
        fatal("minigit repository already exists");
    }
    if (mkdir(MG_DIR, 0755) != 0) {
        fatal("could not create .minigit directory");
    }
    FILE *fp = fopen(INDEX_PATH, "w");
    if (!fp) {
        fatal("could not create index file");
    }
    fclose(fp);
}

void cmd_add(const char *path) {
    struct stat st;
    if (stat(path, &st) != 0) {
        fatal("file does not exist");
    }
    ensure_minigit_dir();
    FILE *fp = fopen(INDEX_PATH, "a");
    if (!fp) {
        fatal("could not open index file");
    }
    fprintf(fp, "%s\n", path);
    fclose(fp);
}

void cmd_ls_files() {
    FILE *fp = fopen(INDEX_PATH, "r");
    if (!fp) {
        fatal("could not open index file");
    }
    char line[1024];
    while (fgets(line, sizeof(line), fp)) {
        line[strcspn(line, "\n")] = '\0';
        printf("%s\n", line);
    }
    fclose(fp);
}

void cmd_commit() {
    ensure_minigit_dir();
    FILE *fp = fopen(INDEX_PATH, "r");
    if (!fp) {
        fatal("could not open index file");
    }
    char line[1024];
    while (fgets(line, sizeof(line), fp)) {
        line[strcspn(line, "\n")] = '\0';
        printf("committed %s\n", line);
    }
    fclose(fp);
    fp = fopen(INDEX_PATH, "w");
    if (!fp) {
        fatal("could not open index file");
    }
    fclose(fp);
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        fatal("usage: minigit <command>");
    }
    const char *cmd = argv[1];
    if (strcmp(cmd, "init") == 0) {
        cmd_init();
    } else if (strcmp(cmd, "add") == 0) {
        if (argc < 3) {
            fatal("usage: minigit add <file>");
        }
        cmd_add(argv[2]);
    } else if (strcmp(cmd, "ls-files") == 0) {
        cmd_ls_files();
    } else if (strcmp(cmd, "commit") == 0) {
        cmd_commit();
    } else {
        fatal("unknown command");
    }
    return 0;
}
